```javascript
// ❌ VULNERABLE CODE
app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

**Risk:** 
- Unauthorized access to PII (Personally Identifiable Information)
- Potential GDPR/privacy law violations
- Email harvesting for spam/phishing campaigns

**Recommendation:**
```javascript
// ✅ SECURE: Add authentication and authorization
const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  // Verify token (implement proper JWT/session validation)
  try {
    const decoded = verifyToken(token); // Use proper JWT library
    req.user = decoded;
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Forbidden' });
  }
};

app.get('/users', authenticate, (req, res) => {
  // Add rate limiting, logging, and pagination
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
