```javascript
require('dotenv').config(); // Only for development
// Production: Use secrets management (AWS Secrets Manager, HashiCorp Vault, etc.)

const dbUrl = process.env.DATABASE_URL;
if (!dbUrl) {
  throw new Error('DATABASE_URL must be set');
}
```

---

#### **6. ⚠️ MEDIUM: No Rate Limiting (OWASP A04:2021 - Insecure Design)**

**Vulnerability:** API endpoints can be brute-forced or hit with DoS attacks.

**Recommendation:**
```javascript
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(limiter);

// Stricter limit for authentication endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
});
app.post('/login', authLimiter, (req, res) => {
  // Handle login
});
```

---

#### **7. ⚠️ MEDIUM: Missing Request Logging & Monitoring (OWASP A09:2021 - Logging and Monitoring Failures)**

**Vulnerability:** No audit trail for debugging security incidents or detecting attacks.

**Recommendation:**
```javascript
const morgan = require('morgan');
const winston = require('winston');

// HTTP request logging
app.use(morgan('combined'));

// Structured logging for security events
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' }),
  ],
});

app.get('/users', authenticate, (req, res) => {
  logger.info('Users endpoint accessed', { userId: req.user.id });
  res.json([...]);
});
```

---

#### **8. ⚠️ MEDIUM: No Error Handling/Stack Trace Exposure (OWASP A01:2021 - Broken Access Control)**

**Vulnerability:** Unhandled errors could expose stack traces and system information.

**Recommendation:**
```javascript
// Global error handler (add after all routes)
app.use((err, req, res, next) => {
  logger.error('Unhandled error', { error: err });

  // Don't expose stack traces to clients
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' 
      ? 'Internal Server Error'
      : err.message,
  });
});

// Catch 404s
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});
```

---

#### **9. ⚠️ MEDIUM: No HTTPS Enforcement**

**Vulnerability:** App doesn't enforce HTTPS, allowing man-in-the-middle attacks.

**Recommendation:**
```javascript
// In production, use a reverse proxy (nginx, Cloudflare) to enforce HTTPS
// Or add middleware:
app.use((req, res, next) => {
  if (process.env.NODE_ENV === 'production' && req.header('x-forwarded-proto') !== 'https') {
    return res.redirect(`https://${req.header('host')}${req.url}`);
  }
  next();
});
```

