      status: 'ok',
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
      // Optional: add dependency checks
    };
    res.status(200).json(health);
  } catch (err) {
    logger.error('Health check failed', { error: err });
    res.status(503).json({ status: 'unavailable' });
  }
});
```

