  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
});
app.use(limiter);
```

---

#### **2. NO AUTHENTICATION/AUTHORIZATION**
**Severity: MEDIUM**

**Issue:** The `/users` endpoint returns sensitive user data (names and emails) without any authentication or authorization checks. This violates the principle of least privilege.

**Recommendation:**
```javascript
const jwt = require('jsonwebtoken');

// Authentication middleware
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Access denied. No token provided.' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Invalid or expired token.' });
  }
};

app.get('/users', authenticateToken, (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

---

#### **3. MISSING HTTPS/TLS**
**Severity: HIGH**

**Issue:** The application only listens on HTTP (port 3000). This exposes all data in transit to man-in-the-middle (MITM) attacks.

**Recommendation:**
```javascript
const https = require('https');
